import React, { useState } from 'react';

export default function UploadPanel({ onAnalyze, loading, error }) {
  const [file, setFile] = useState(null);
  const [dragging, setDragging] = useState(false);

  const handleDrop = (e) => {
    e.preventDefault();
    setDragging(false);
    const dropped = e.dataTransfer.files[0];
    if (dropped) setFile(dropped);
  };

  return (
    <div style={{ maxWidth: 600, margin: '3rem auto', padding: '0 1.5rem', fontFamily: 'Inter, sans-serif' }}>
      <div
        onDragOver={e => { e.preventDefault(); setDragging(true); }}
        onDragLeave={() => setDragging(false)}
        onDrop={handleDrop}
        onClick={() => document.getElementById('file-input').click()}
        style={{ border: `2px dashed ${dragging ? '#1d9e75' : '#ccc'}`, borderRadius: 12, padding: '3rem 2rem', textAlign: 'center', cursor: 'pointer', background: dragging ? '#f0fdf8' : '#fff', transition: 'all 0.15s', marginBottom: 16 }}
      >
        <div style={{ fontSize: 40, marginBottom: 12 }}>📂</div>
        <p style={{ fontSize: 15, color: '#555', marginBottom: 6 }}>Drop a file or click to upload</p>
        <span style={{ fontSize: 12, color: '#aaa' }}>.py · .js · .java · .cpp · .ts · .go · .php · and more</span>
      </div>
      <input id="file-input" type="file" style={{ display: 'none' }} onChange={e => setFile(e.target.files[0])} />

      {file && (
        <div style={{ background: '#f0fdf8', border: '1px solid #5dcaa5', borderRadius: 8, padding: '0.75rem 1rem', marginBottom: 16, fontSize: 13, color: '#0f6e56' }}>
          ✓ Selected: <strong>{file.name}</strong>
        </div>
      )}

      {error && (
        <div style={{ background: '#fcebeb', border: '1px solid #f09595', borderRadius: 8, padding: '0.75rem 1rem', marginBottom: 16, fontSize: 13, color: '#a32d2d' }}>
          ⚠ {error}
        </div>
      )}

      <button
        onClick={() => file && onAnalyze(file)}
        disabled={loading || !file}
        style={{ width: '100%', padding: 12, fontSize: 15, fontWeight: 600, border: 'none', borderRadius: 8, background: loading || !file ? '#ccc' : '#1d9e75', color: '#fff', cursor: loading || !file ? 'not-allowed' : 'pointer' }}
      >
        {loading ? '⏳ Analyzing...' : '🔍 Analyze for Vulnerabilities'}
      </button>
    </div>
  );
}
